const item = $node["Get a message"].json;
let messageContent = item.body.content;

// If content is HTML, extract text between <body> or <div> tags
if (item.body.contentType === "html") {
  // Simple regex to extract content before quoted replies
  const match = messageContent.match(/<body[^>]*>(.*?)(?:<div[^>]*class="gmail_quote"|<hr[^>]*>|From:)/is);
  messageContent = match ? match[1].replace(/<[^>]+>/g, '').trim() : messageContent.replace(/<[^>]+>/g, '').trim();
}

// Remove extra whitespace and newlines
messageContent = messageContent.replace(/\s+/g, ' ').trim();

// Return formatted output
return [{
  json: {
    subject:item.subject,
    name: item.sender.emailAddress.name || "Unknown",
    email: item.sender.emailAddress.address,
    date: item.receivedDateTime,
    message: messageContent
  }
}];

const input = $input.first();

// Parse the JSON string if necessary
let findname = input.json.findname;

if (typeof findname === 'string') {
  try {
    findname = JSON.parse(findname);
  } catch (e) {
    findname = {};
  }
}

// Now extract the fileName
const fileName = findname?.data?.fileName || 'no-filename';

return [
  {
    json: {
      filename: fileName
    }
  }
];

// Output array to store split attachments
const out = [];

for (const inItem of items) {
  // Get all binary data in the current item (email, etc.)
  const binaries = inItem.binary ?? {};

  for (const [key, bin] of Object.entries(binaries)) {
    out.push({
      json: {
        sourceEmailIndex: inItem.$index,
        originalKey: key,
      },
      binary: {
        data: bin, // n8n will look for 'data' key in binary
      },
    });
  }
}

return out;

const crypto = require('crypto');

// Take conversationId from the first input item
const item = $input.first().json;
const conversationId = item.conversationId || '';

// Use only conversationId for deterministic ID
const inputString = conversationId;

// Generate MD5 hash
const hash = crypto.createHash('md5').update(inputString).digest('hex');

// Convert hash to a number and extract 6 digits
const numericValue = parseInt(hash.substring(0, 8), 16); // safer size
const sixDigitId = (numericValue % 1000000).toString().padStart(6, '0');

// Add index and ticketNo to all items
return items.map((item, index) => {
  item.json.index = index;
  item.json.ticketNo = sixDigitId;
  return item;
});

const crypto = require('crypto');

// Take conversationId from the first input item
const item = $input.first().json;
const conversationId = item.conversationId || '';

// Use only conversationId for deterministic ID
const inputString = conversationId;

// Generate MD5 hash
