const items = $input.all();
console.log('Processing items:', items.length);

// Separate attachments from ticket info
const attachments = [];
let ticketInfo = null;

for (const item of items) {
  if (item.json.complete) {
    try {
      const parsed = JSON.parse(item.json.complete);

      // Check if this is an attachment
      if (parsed.fileName && parsed.fileData) {
        attachments.push({
          fileName: parsed.fileName,
          fileData: parsed.fileData,
          result: parsed.result || false
        });
      }
      // Check if this is ticket information
      else if (parsed.ticket_id) {
        // Remove all instances of (Ticket ID: XYZ) anywhere in the draft
        let cleanDraft = parsed.draft || '';


        // Optional: Normalize multiple line breaks or fix spacing if needed
        cleanDraft = cleanDraft.replace(/\n{2,}/g, '\n\n'); // ensure max two line breaks
        cleanDraft = cleanDraft.replace(/[ \t]+\n/g, '\n'); // remove trailing spaces before newline

        ticketInfo = {
          ...parsed,
          draft: cleanDraft
        };
      }
    } catch (error) {
      console.log('Error parsing JSON:', error);
    }
  }
}

console.log('Found attachments:', attachments.length);
console.log('Found ticket info:', ticketInfo ? 'Yes' : 'No');

// If we have both ticket info and attachments, combine them
if (ticketInfo && attachments.length > 0) {
  const combinedTicket = {
    ...ticketInfo,
    attachments: attachments
  };

  return [{
    json: combinedTicket
  }];
}

// If we only have ticket info (no attachments)
else if (ticketInfo) {
  return [{
    json: {
      ...ticketInfo,
      attachments: []
    }
  }];
}

// If we only have attachments (no ticket info)
else if (attachments.length > 0) {
  return [{
    json: {
      ticket_id: `file-${Date.now()}`,
      name: 'File Upload User',
      from: 'fileupload@system.com',
      body: `Uploaded ${attachments.length} file(s): ${attachments.map(a => a.fileName).join(', ')}`,
      Classification: 'File Upload',
      Priority: 'Medium',
      date: new Date().toISOString(),
      threadId: '',
      messageid: `msg-${Date.now()}`,
      attachments: attachments
    }
  }];
}

// No valid data found
else {
  return [{
    json: {
      error: 'No valid ticket or attachment data found'
    }
  }];
}

// Get the HTML content from the input
const htmlContent = $input.first().json.body.content || '';

// Function to decode HTML entities
function decodeHTMLEntities(text) {
  const entities = {
    '&amp;': '&',
    '&lt;': '<',
    '&gt;': '>',
    '&quot;': '"',
    '&apos;': "'",
    '&#39;': "'",
    '&nbsp;': ' ',
    '&mdash;': '—',
    '&ndash;': '–',
    '&rsquo;': "'",
    '&lsquo;': "'",
    '&rdquo;': '"',
    '&ldquo;': '"',
    '&hellip;': '...',
  };

  return text.replace(/&[#\w]+;/g, entity => entities[entity] || entity);
}

// Function to remove HTML tags and extract text
function extractTextFromHTML(html) {
  if (!html) return '';

  // Remove script and style tags with their content
  let text = html.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');
  text = text.replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, '');

  // Remove HTML comments
  text = text.replace(/<!--[\s\S]*?-->/g, '');

  // Replace common block elements with newlines
  text = text.replace(/<\/(div|p|h[1-6]|li|tr|br)>/gi, '\n');
  text = text.replace(/<br\s*\/?>/gi, '\n');

  // Remove all remaining HTML tags
  text = text.replace(/<[^>]+>/g, '');

  // Decode HTML entities
  text = decodeHTMLEntities(text);

  // Clean up whitespace
  text = text.replace(/\n\s*\n/g, '\n\n'); // Remove excessive newlines
  text = text.replace(/[ \t]+/g, ' '); // Normalize spaces
  text = text.trim();

  return text;
}

// Function to extract specific attributes
function extractAttributes(html) {
  const attributes = {};

  // Extract text from title tags
  const titleMatch = html.match(/<title[^>]*>(.*?)<\/title>/i);
  if (titleMatch) attributes.title = titleMatch[1].trim();

  // Extract meta descriptions
  const metaDescMatch = html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)["']/i);
  if (metaDescMatch) attributes.metaDescription = metaDescMatch[1];

  // Extract all links
  const links = [];
  const linkRegex = /<a[^>]*href=["']([^"']*)["'][^>]*>(.*?)<\/a>/gi;
  let linkMatch;
  while ((linkMatch = linkRegex.exec(html)) !== null) {
    links.push({
      url: linkMatch[1],
      text: extractTextFromHTML(linkMatch[2])
    });
  }
  if (links.length > 0) attributes.links = links;

  return attributes;
}

// Extract everything
const extractedText = extractTextFromHTML(htmlContent);

// Return the result
return {
  json: {
    extractedText: extractedText
  }
};

const crypto = require('crypto');
const items = $input.all(); // Get all items from the loop

let existingTicketId = null;

// Function to extract ticket IDs from message
function extractTicketIds(text) {
  // NEW FORMAT: M + 5 alphanumeric chars (e.g. M6AA2F, M7F499)
  const newPattern = /M[A-Z0-9]{5}/g;
  const newMatches = text.match(newPattern);
  if (newMatches && newMatches.length > 0) return newMatches;

  // OLD FORMAT fallback: 2 letters from [E,W,T,S,G,O] + 4 digits
  const oldPattern = /[EWTSG0]{2}\d{4}/g;
  const oldMatches = text.match(oldPattern);
  return oldMatches || [];
}

// Loop through all iterations to find existing ticket ID
for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  const message = item.message || "";

  // Extract ticket IDs from this iteration's message
  const ticketIds = extractTicketIds(message);

  if (ticketIds.length > 0) {
    // Found a ticket ID in one of the iterations
    existingTicketId = ticketIds[0];
    break; // Stop searching once we find a ticket
  }
}

// If we found an existing ticket ID in any iteration, return it
if (existingTicketId) {
  return [{
    json: {
      ticketNo: existingTicketId,
      source: "existing" // Optional: indicates this was found, not generated
    }
  }];
}

// If no ticket found in any iteration, generate a new ticket number
// NEW FORMAT: M + 5 random uppercase hex chars
const firstItem = items[0].json;
const conversationId = firstItem.conversationId || "";
const salt = Date.now().toString() + Math.random().toString();
const inputString = conversationId + salt;
const hash = crypto.createHash('md5').update(inputString).digest('hex');
const ticketNo = 'M' + hash.substring(0, 5).toUpperCase();

return [{
  json: {
    ticketNo,
    source: "generated" // Optional: indicates this was newly generated
  }
}];
